describe('ChunkManager', () => {
    let manager: ChunkManager;
    let mockStrapi: any;
    let mockQuery: any;
    let mockDocuments: any;

    beforeEach(() => {
        vi.clearAllMocks();

        // Reset Singleton
        (ChunkManager as any).instance = null;

        mockQuery = {
            create: vi.fn(),
        };
        mockDocuments = {
            findMany: vi.fn(),
        };

        mockStrapi = {
            db: { query: vi.fn(() => mockQuery) },
            documents: vi.fn(() => mockDocuments),
        };
        (global as any).strapi = mockStrapi;

        manager = ChunkManager.getInstance();
    });

    it('should be a singleton', () => {
        const instance2 = ChunkManager.getInstance();
        expect(manager).toBe(instance2);
    });

    describe('getChunk', () => {
        it('should fetch chunk via worker and cache it', async () => {
             const config = { seed: 'test-seed', chunkSize: 16 } as any;
             const mockChunk = { x: 0, y: 0, tiles: [] };

             // Setup Worker response
             mockWorker.postMessage.mockImplementation(({ id }) => {
                 const handler = mockWorker.on.mock.calls.find(call => call[0] === 'message')[1];
                 handler({ id, success: true, result: mockChunk, seed: 'test-seed' });
             });

             const chunk = await manager.getChunk(0, 0, config);
             expect(chunk).toEqual(mockChunk);

             // Verify caching
             mockWorker.postMessage.mockClear();
             const cached = await manager.getChunk(0, 0, config);
             expect(cached).toEqual(mockChunk);
             expect(mockWorker.postMessage).not.toHaveBeenCalled();
        });

        it('should handle worker errors', async () => {
             const config = { seed: 'test-seed' } as any;
             mockWorker.postMessage.mockImplementation(({ id }) => {
                 const handler = mockWorker.on.mock.calls.find(call => call[0] === 'message')[1];
                 handler({ id, success: false, error: 'Worker Failed' });
             });

             await expect(manager.getChunk(0, 0, config)).rejects.toThrow('Worker Failed');
        });

        it('should handle worker crash event', async () => {
             const config = { seed: 'test-seed' } as any;
             // We trigger error on worker
             mockWorker.postMessage.mockImplementation(({ id }) => {
                 // Trigger global error handler
                 const handler = mockWorker.on.mock.calls.find(call => call[0] === 'error')[1];
                 handler(new Error('Worker Crash'));
             });

             await expect(manager.getChunk(0, 0, config)).rejects.toThrow('Worker Crash');
        });

        it('should apply persisted changes on top of generated chunk', async () => {
             const config = { seed: 'persist-seed' } as any;
             // Deep copyable structure
             const tiles = Array.from({ length: 7 }, () => 
                 Array.from({ length: 16 }, () => 
                     Array.from({ length: 16 }, () => ({ block: BlockType.AIR }))
                 )
             );
             const mockChunk = { x: 0, y: 0, tiles };

             // Mock persistence fetch
             const changes = [{
                 chunkX: 0, chunkY: 0,
                 voxelX: 0, voxelY: 0, voxelZ: 0, // zIndex 3
                 newType: BlockType.FLOOR_STONE,
                 metadata: { meta: 'persisted' }
             }];
             mockDocuments.findMany.mockResolvedValue(changes);

             // Worker returns base chunk
             mockWorker.postMessage.mockImplementation(({ id }) => {
                 const handler = mockWorker.on.mock.calls.find(call => call[0] === 'message')[1];
                 // Return deep copy to ensure isolation
                 handler({ id, success: true, result: JSON.parse(JSON.stringify(mockChunk)), seed: 'persist-seed' });
             });

             const chunk = await manager.getChunk(0, 0, config, 'world-1');

             expect(chunk.tiles[3][0][0].block).toBe(BlockType.FLOOR_STONE);
             expect(chunk.tiles[3][0][0].metadata).toEqual({ meta: 'persisted' });
        });
    });

    describe('applyVoxelChanges', () => {
        it('should verify bounds and apply changes', () => {
            const tiles = Array.from({ length: 7 }, () => 
                Array.from({ length: 16 }, () => 
                    Array.from({ length: 16 }, () => ({ block: BlockType.AIR }))
                )
            );
            const chunk = { x: 0, y: 0, tiles } as any;

            const changes = [
                // Valid
                { chunkX:0, chunkY:0, voxelX:5, voxelY:5, voxelZ:0, newType: BlockType.FLOOR_WOOD },
                // Invalid Bounds
                { chunkX:0, chunkY:0, voxelX:20, voxelY:5, voxelZ:0, newType: BlockType.BEDROCK },
                { chunkX:0, chunkY:0, voxelX:5, voxelY:5, voxelZ:10, newType: BlockType.BEDROCK },
            ];

            manager.applyVoxelChanges(chunk, changes);

            expect(chunk.tiles[3][5][5].block).toBe(BlockType.FLOOR_WOOD);
            // Should stay defaults (implicitly tested by not crashing or polluting)
        });
    });

    describe('editVoxel', () => {
        it('should persist change and update cache', async () => {
             const chunkX = 1, chunkY = 1;
             const tiles = Array.from({ length: 7 }, () => 
                Array.from({ length: 16 }, () => 
                    Array.from({ length: 16 }, () => ({ block: BlockType.AIR }))
                )
            );
             const chunk = { x: chunkX, y: chunkY, tiles } as any;
             (manager as any).addToCache(chunkX, chunkY, 'seed', chunk);

             await manager.editVoxel(chunkX, chunkY, 0, 0, 0, BlockType.GRASS, 'world-1', 'player');

             expect(mockQuery.create).toHaveBeenCalledWith(expect.objectContaining({
                 data: expect.objectContaining({
                     chunkX, chunkY,
                     voxelX: 0, voxelY: 0, voxelZ: 0,
                     newType: BlockType.GRASS,
                     world: 'world-1'
                 })
             }));

             expect(chunk.tiles[3][0][0].block).toBe(BlockType.GRASS);
        });

        it('should fail over to dirt if type undefined and not in cache', async () => {
             const spy = vi.spyOn(console, 'warn').mockImplementation(() => {});

             // No cache (cleared in beforeEach by new instance)
             await manager.editVoxel(99, 99, 0, 0, 0, undefined, 'world-1');

             expect(spy).toHaveBeenCalled();
             expect(mockQuery.create).toHaveBeenCalledWith(expect.objectContaining({
                 data: expect.objectContaining({
                     newType: 'dirt'
                 })
             }));
        });

        it('should resolve type from cache if undefined in request', async () => {
             const chunkX = 2, chunkY = 2;
             const tiles = Array.from({ length: 7 }, () => 
                Array.from({ length: 16 }, () => 
                    Array.from({ length: 16 }, () => ({ block: BlockType.STONE }))
                )
            );
             const chunk = { x: chunkX, y: chunkY, tiles } as any;
             (manager as any).addToCache(chunkX, chunkY, 'seed', chunk);

             // Request update with NO type (metadata only usually, but here checking type resolution)
             await manager.editVoxel(chunkX, chunkY, 0, 0, 0, undefined, 'world-1', 'meta-upd');

             expect(mockQuery.create).toHaveBeenCalledWith(expect.objectContaining({
                 data: expect.objectContaining({
                     newType: BlockType.STONE // Solved from cache
                 })
             }));
        });
    });
});

import { describe, it, expect } from 'vitest';
import fs from 'fs';
import path from 'path';
import { SchemaLoader } from '@/features/genesis-core/schema-loader';
import { DryRunService } from '@/features/genesis-core/dry-run-service';
import { GenesisManifest } from '@/features/genesis-core/audit-service';

describe('Genesis Integrity', () => {
    const manifestPath = path.resolve(process.cwd(), 'genesis-manifest.json');

    if (!fs.existsSync(manifestPath)) {
        it.skip('Manifest not found, skipping integrity tests', () => {});
        return;
    }

    const manifestData = fs.readFileSync(manifestPath, 'utf-8');
    const manifest: GenesisManifest = JSON.parse(manifestData);

    const loader = new SchemaLoader();
    const dryRun = new DryRunService(loader);

    const checkEntityCoverage = async (type: string, uid: string) => {
        const entities = manifest.entities.filter(e => e.type === type);
        const missing: string[] = [];
        const invalid: string[] = [];

        for (const entity of entities) {
            const filePath = path.resolve(process.cwd(), 'seed-data', type, `${entity.index}.json`);
            if (!fs.existsSync(filePath)) {
                missing.push(entity.name);
                continue;
            }

            try {
                const content = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
                // Validate against Strapi Schema
                // Note: We might need to map type -> UID if it differs (e.g. monster -> api::monster.monster)
                const validation = await dryRun.validate(content, uid);
                if (!validation.valid) {
                     invalid.push(`${entity.name}: ${validation.errors.join(', ')}`);
                }
            } catch (e) {
                invalid.push(`${entity.name}: Malformed JSON`);
            }
        }

        return { total: entities.length, missing, invalid };
    };

    describe('Spells Coverage', () => {
        it('should track spell generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('spell', 'api::spell.spell');
            console.log(`Spells: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);

            // Assertion: We expect at least the ones we generated manually to exist
            const acidArrowPath = path.resolve(process.cwd(), 'seed-data/spell/acid-arrow.json');
            expect(fs.existsSync(acidArrowPath)).toBe(true);
        });
    });

    describe('Items Coverage', () => {
        it('should track item generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('item', 'api::item.item');
            console.log(`Items: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);

             const clubPath = path.resolve(process.cwd(), 'seed-data/item/club.json');
             expect(fs.existsSync(clubPath)).toBe(true);
        });
    });

    describe('Features Coverage', () => {
        it('should track feature generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('feature', 'api::feature.feature');
            console.log(`Features: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);
        });
    });

    describe('Traits Coverage', () => {
         it('should track trait generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('trait', 'api::trait.trait');
            console.log(`Traits: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);
        });
    });

    describe('Monsters Coverage', () => {
         it('should track monster generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('monster', 'api::monster.monster');
            console.log(`Monsters: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);
        });
    });

    describe('Races Coverage', () => {
         it('should track race generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('race', 'api::race.race');
            console.log(`Races: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);
        });
    });

    describe('Classes Coverage', () => {
         it('should track class generation progress', async () => {
            const { total, missing, invalid } = await checkEntityCoverage('class', 'api::class.class');
            console.log(`Classes: ${total - missing.length}/${total} generated. Invalid: ${invalid.length}`);
        });
    });
});

